import{_ as e,o as r,c as a,a2 as d}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),o={name:"guide/getting-started.md"};function l(i,t,s,n,c,h){return r(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><h2 id="下载与安装" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装" aria-label="Permalink to &quot;下载与安装&quot;">​</a></h2><ol><li>从 <a href="https://github.com/bnganblog/xkbtool/releases/latest" target="_blank" rel="noreferrer">GitHub Release</a> 下载最新版 <code>XKBToolbox.zip</code></li><li>解压到任意目录（建议非系统盘）</li><li>双击运行 <code>ToolboxWinUI.exe</code></li></ol><div class="tip custom-block"><p class="custom-block-title">首次运行</p><p>如果系统未安装 .NET 10 Desktop Runtime，会自动提示安装。</p></div><h2 id="界面导航" tabindex="-1">界面导航 <a class="header-anchor" href="#界面导航" aria-label="Permalink to &quot;界面导航&quot;">​</a></h2><p>启动后默认显示 <strong>系统信息</strong> 页面，左侧为导航栏：</p><table tabindex="0"><thead><tr><th>导航项</th><th>功能</th></tr></thead><tbody><tr><td>系统信息</td><td>查看 CPU、内存、GPU、硬盘等硬件信息及用量</td></tr><tr><td>收藏夹</td><td>快速访问已收藏的工具</td></tr><tr><td>CPU工具</td><td>CPU 相关检测与优化工具</td></tr><tr><td>显卡工具</td><td>GPU 相关检测与优化工具</td></tr><tr><td>内存工具</td><td>内存检测与优化工具</td></tr><tr><td>硬盘工具</td><td>硬盘检测与管理工具</td></tr><tr><td>外设工具</td><td>鼠标、键盘等外设工具</td></tr><tr><td>烤鸡工具</td><td>稳定性测试工具</td></tr><tr><td>网络工具</td><td>IP 查询、分流测试、网速测试</td></tr><tr><td>其他工具</td><td>其他实用工具</td></tr><tr><td>工具商店</td><td>下载安装插件扩展</td></tr></tbody></table><h2 id="使用工具" tabindex="-1">使用工具 <a class="header-anchor" href="#使用工具" aria-label="Permalink to &quot;使用工具&quot;">​</a></h2><p>每个工具以卡片形式展示，包含：</p><ul><li><strong>图标</strong> — 工具标识</li><li><strong>名称</strong> — 工具名称</li><li><strong>描述</strong> — 工具简介</li><li><strong>⭐ 收藏</strong> — 点击星标收藏工具</li><li><strong>⚙ 设置</strong> — 编辑工具信息</li><li><strong>打开</strong> — 启动工具</li></ul><h2 id="添加自定义工具" tabindex="-1">添加自定义工具 <a class="header-anchor" href="#添加自定义工具" aria-label="Permalink to &quot;添加自定义工具&quot;">​</a></h2><ol><li>将工具文件放入 <code>tools/</code> 目录</li><li>点击左侧导航栏对应分类</li><li>工具会自动出现在卡片网格中</li></ol><p>也可以在 设置 → 工具管理 中导入/导出工具配置。</p>',13)])])}const p=e(o,[["render",l]]);export{b as __pageData,p as default};
